package org.jetbrains.kotlin.analysis.api.components

import org.jetbrains.kotlin.analysis.api.*
import org.jetbrains.kotlin.analysis.api.projectStructure.KaModule
import org.jetbrains.kotlin.analysis.api.scopes.KaScope

/**
 * Provides declarations generated by compiler plugins.
 */
@KaExperimentalApi
@KaSessionComponentImplementationDetail
@SubclassOptInRequired(KaSessionComponentImplementationDetail::class)
public interface KaCompilerPluginGeneratedDeclarationsProvider : KaSessionComponent {
    /**
     * [Declarations][KaCompilerPluginGeneratedDeclarations] generated by compiler plugins for [this] module, not including the generated
     * declarations for *dependencies* of this module.
     */
    @KaExperimentalApi
    public val KaModule.compilerPluginGeneratedDeclarations: KaCompilerPluginGeneratedDeclarations
}

/**
 * **The type has been moved to a new package. Use [org.jetbrains.kotlin.analysis.api.compilerPlugins.KaCompilerPluginGeneratedDeclarations] instead.**
 *
 * Represents declarations generated by compiler plugins.
 *
 * @see KaCompilerPluginGeneratedDeclarationsProvider
 */
@KaObsoleteComponentApi
@KaExperimentalApi
@SubclassOptInRequired(KaImplementationDetail::class)
public interface KaCompilerPluginGeneratedDeclarations :
    org.jetbrains.kotlin.analysis.api.compilerPlugins.KaCompilerPluginGeneratedDeclarations {
    /**
     * A [KaScope] containing the top-level declarations generated by compiler plugins.
     */
    override val topLevelDeclarationsScope: KaScope
}

/**
 * [Declarations][KaCompilerPluginGeneratedDeclarations] generated by compiler plugins for [this] module, not including the generated
 * declarations for *dependencies* of this module.
 */
@Deprecated(
    message = "Use the 'org.jetbrains.kotlin.analysis.api.compilerPlugins' endpoint instead.",
    replaceWith = ReplaceWith(
        "this.compilerPluginGeneratedDeclarations",
        "org.jetbrains.kotlin.analysis.api.compilerPlugins.compilerPluginGeneratedDeclarations",
    ),
)
@KaExperimentalApi
@KaContextParameterApi
context(session: KaSession)
public val KaModule.compilerPluginGeneratedDeclarations: KaCompilerPluginGeneratedDeclarations
    get() = with(session) { compilerPluginGeneratedDeclarations }
